        EventId = 100,
        Level = LogLevel.Information,
        EventName = "TodoListCreated",
        Message = "TodoList created - Id: {Id}, Name: {Name}"
    )]
    public static partial void LogTodoListCreated(this ILogger logger, Guid id, string name);
}

